  <script>
    // ==================== COIN RENDERER ====================

    function createCoinRenderer(canvas, isHero = false) {
      const ctx = canvas.getContext('2d');
      let rotationAngle = 0;
      let flipProgress = 0; // 0 to 1 (0 = front, 0.5 = side, 1 = back)
      let time = 0;

      // Procedural texture generation
      function createNoiseTexture(size) {
        const offCanvas = document.createElement('canvas');
        offCanvas.width = size;
        offCanvas.height = size;
        const offCtx = offCanvas.getContext('2d');

        for (let i = 0; i < size * size / 4; i++) {
          const x = Math.random() * size;
          const y = Math.random() * size;
          const alpha = Math.random() * 0.15;

          offCtx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
          offCtx.fillRect(x, y, 2, 2);
        }

        return offCanvas;
      }

      const noiseTexture = createNoiseTexture(64);

      // Draw coin face
      function drawFace(ctx, isFront) {
        ctx.save();

        // Base metal color
        if (isHero) {
          // Hero uses dynamic colors based on flip state
          const goldRatio = Math.sin(rotationAngle * 0.5 + time);
          const silverRatio = Math.cos(rotationAngle * 0.5 + time);

          // Dynamic gradient for hero coin
          const gradient = ctx.createRadialGradient(150, 150, 20, 150, 150, 140);
          if (isFront) {
            gradient.addColorStop(0, '#ffd700');
            gradient.addColorStop(0.3, '#d4af37');
            gradient.addColorStop(0.6, '#b8962e');
            gradient.addColorStop(1, '#8a7520');
          } else {
            gradient.addColorStop(0, '#c0c0c0');
            gradient.addColorStop(0.3, '#a0a0a0');
            gradient.addColorStop(0.6, '#808080');
            gradient.addColorStop(1, '#5a5a5a');
          }

          ctx.fillStyle = gradient;
        } else {
          // Edition coins use static colors
          const type = canvas.parentElement.parentElement.dataset.edition;
          if (type === 'bronze') {
            const bronzeGradient = ctx.createRadialGradient(150, 150, 20, 150, 150, 140);
            bronzeGradient.addColorStop(0, '#cd7f32');
            bronzeGradient.addColorStop(0.3, '#b86a2d');
            bronzeGradient.addColorStop(0.6, '#9e5b26');
            bronzeGradient.addColorStop(1, '#74421c');
            ctx.fillStyle = bronzeGradient;
          } else if (type === 'silver') {
            const silverGradient = ctx.createRadialGradient(150, 150, 20, 150, 150, 140);
            silverGradient.addColorStop(0, '#e8e9f3');
            silverGradient.addColorStop(0.3, '#c0c0c0');
            silverGradient.addColorStop(0.6, '#a0a0a0');
            silverGradient.addColorStop(1, '#7a7a7a');
            ctx.fillStyle = silverGradient;
          } else if (type === 'gold') {
            const goldGradient = ctx.createRadialGradient(150, 150, 20, 150, 150, 140);
            goldGradient.addColorStop(0, '#ffd700');
            goldGradient.addColorStop(0.3, '#e6c200');
            goldGradient.addColorStop(0.6, '#ccad00');
            goldGradient.addColorStop(1, '#a38900');
            ctx.fillStyle = goldGradient;
          } else if (type === 'black') {
            const blackGradient = ctx.createRadialGradient(150, 150, 20, 150, 150, 140);
            blackGradient.addColorStop(0, '#3a3b45');
            blackGradient.addColorStop(0.3, '#25262e');
            blackGradient.addColorStop(0.6, '#1a1b23');
            blackGradient.addColorStop(1, '#0f0f15');
            ctx.fillStyle = blackGradient;
          }
        }

        // Draw coin face circle
        ctx.beginPath();
        ctx.arc(150, 150, 140, 0, Math.PI * 2);
        ctx.fill();

        // Add inner ring for detail
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.arc(150, 150, 120, 0, Math.PI * 2);
        ctx.stroke();

        // Draw embossed design
        if (isFront) {
          // WastedToken Mint emblem
          ctx.save();

          // Outer ring with text
          ctx.strokeStyle = 'rgba(255, 255, 255, 0.8)';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.arc(150, 150, 90, 0, Math.PI * 2);
          ctx.stroke();

          // WTM monogram
          ctx.fillStyle = '#fff';
          ctx.font = 'bold 48px Courier New';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';

          // Create embossed effect with shadow
          ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
          ctx.shadowBlur = 6;
          ctx.shadowOffsetX = 2;
          ctx.shadowOffsetY = 2;

          ctx.fillText('WTM', 150, 150);

          // Inner circle
          ctx.beginPath();
          ctx.arc(150, 150, 40, 0, Math.PI * 2);
          ctx.fillStyle = 'rgba(255, 255, 255, 0.1)';
          ctx.fill();

          // Token count
          ctx.shadowColor = 'transparent';
          ctx.font = 'bold 16px Courier New';
          ctx.fillText('10,000 TOKENS', 150, 230);

          ctx.restore();
        } else {
          // Back face - token count and design
          ctx.save();

          // Token count with embossed effect
          ctx.fillStyle = '#fff';
          ctx.font = 'bold 48px Courier New';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';

          ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
          ctx.shadowBlur = 6;
          ctx.shadowOffsetX = 2;
          ctx.shadowOffsetY = 2;

          ctx.fillText('10,000 TOKENS', 150, 130);

          // Decorative elements
          ctx.strokeStyle = 'rgba(255, 255, 255, 0.6)';
          ctx.lineWidth = 2;

          for (let i = 0; i < 8; i++) {
            const angle = (i / 8) * Math.PI * 2;
            const x1 = 150 + 70 * Math.cos(angle);
            const y1 = 150 + 70 * Math.sin(angle);
            const x2 = 150 + 110 * Math.cos(angle);
            const y2 = 150 + 110 * Math.sin(angle);

            ctx.beginPath();
            ctx.moveTo(x1, y1);
            ctx.lineTo(x2, y2);
            ctx.stroke();
          }

          // Inner circle
          ctx.beginPath();
          ctx.arc(150, 150, 40, 0, Math.PI * 2);
          ctx.fillStyle = 'rgba(255, 255, 255, 0.1)';
          ctx.fill();

          // WTM text on back
          ctx.shadowColor = 'transparent';
          ctx.font = 'bold 24px Courier New';
          ctx.fillText('WASTEDTOKEN', 150, 230);

          ctx.restore();
        }

        ctx.restore();
      }

      // Draw reeded edge
      function drawReededEdge(ctx) {
        const numTeeth = 60;
        const outerRadius = 148;
        const innerRadius = 140;

        for (let i = 0; i < numTeeth; i++) {
          const angle = (i / numTeeth) * Math.PI * 2 + rotationAngle;

          ctx.save();
          ctx.translate(150, 150);
          ctx.rotate(angle);

          // Draw each tooth
          ctx.beginPath();
          ctx.moveTo(innerRadius, -6);
          ctx.lineTo(outerRadius, -8);
          ctx.lineTo(outerRadius, 8);
          ctx.lineTo(innerRadius, 6);
          ctx.closePath();

          if (isHero) {
            const gradient = ctx.createLinearGradient(0, -10, 0, 10);
            gradient.addColorStop(0, '#ffd700');
            gradient.addColorStop(0.5, '#ffffff');
            gradient.addColorStop(1, '#b8962e');
            ctx.fillStyle = gradient;
          } else {
            const type = canvas.parentElement.parentElement.dataset.edition;
            if (type === 'bronze') {
              const gradient = ctx.createLinearGradient(0, -10, 0, 10);
              gradient.addColorStop(0, '#cd7f32');
              gradient.addColorStop(0.5, '#e89a4d');
              gradient.addColorStop(1, '#a66b2a');
              ctx.fillStyle = gradient;
            } else if (type === 'silver') {
              const gradient = ctx.createLinearGradient(0, -10, 0, 10);
              gradient.addColorStop(0, '#e8e9f3');
              gradient.addColorStop(0.5, '#ffffff');
              gradient.addColorStop(1, '#a0a0a0');
              ctx.fillStyle = gradient;
            } else if (type === 'gold') {
              const gradient = ctx.createLinearGradient(0, -10, 0, 10);
              gradient.addColorStop(0, '#ffd700');
              gradient.addColorStop(0.5, '#ffed4e');
              gradient.addColorStop(1, '#ccad00');
              ctx.fillStyle = gradient;
            } else if (type === 'black') {
              const gradient = ctx.createLinearGradient(0, -10, 0, 10);
              gradient.addColorStop(0, '#3a3b45');
              gradient.addColorStop(0.5, '#4a4b55');
              gradient.addColorStop(1, '#2a2b35');
              ctx.fillStyle = gradient;
            }
          }

          ctx.fill();
          ctx.restore();
        }
      }

      // Draw specular highlight
      function drawSpecularHighlight(ctx) {
        const angle = rotationAngle + time * 0.5;
        const x = 150 + 80 * Math.cos(angle);
        const y = 150 - 60 * Math.sin(angle);

        ctx.save();

        // Create highlight gradient
        const gradient = ctx.createRadialGradient(x, y, 5, x, y, 40);
        gradient.addColorStop(0, 'rgba(255, 255, 255, 0.8)');
        gradient.addColorStop(0.3, 'rgba(255, 255, 255, 0.4)');
        gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

        ctx.fillStyle = gradient;

        // Draw highlight on coin surface
        ctx.beginPath();
        ctx.arc(150, 150, 140, 0, Math.PI * 2);
        ctx.clip();
        ctx.fillRect(x - 60, y - 60, 120, 120);

        // Add secondary highlight for depth
        const angle2 = rotationAngle + time * 0.5 + Math.PI / 3;
        const x2 = 150 + 70 * Math.cos(angle2);
        const y2 = 150 - 50 * Math.sin(angle2);

        ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.beginPath();
        ctx.arc(x2, y2, 20, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
      }

      // Draw shadow
      function drawShadow(ctx) {
        if (!isHero) return;

        const shadowScale = 1 - flipProgress;
        const shadowY = 350 + (flipProgress > 0.5 ? (flipProgress - 0.5) * 20 : 0);

        ctx.save();
        ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';

        // Elliptical shadow
        ctx.beginPath();
        ctx.ellipse(300, shadowY, 160 * shadowScale, 40 * shadowScale, 0, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
      }

      // Main render function
      function render() {
        // Clear canvas with background color
        if (isHero) {
          ctx.fillStyle = '#1a1c23';
        } else {
          const type = canvas.parentElement.parentElement.dataset.edition;
          if (type === 'bronze') ctx.fillStyle = '#1e1810';
          else if (type === 'silver') ctx.fillStyle = '#16171d';
          else if (type === 'gold') ctx.fillStyle = '#231b0a';
          else if (type === 'black') ctx.fillStyle = '#15161c';
        }
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Calculate flip transformation
        const flipAngle = Math.sin(flipProgress * Math.PI) * Math.PI / 2;

        ctx.save();
        ctx.translate(canvas.width / 2, canvas.height / 2);

        // Apply rotation and flip transformations
        if (isHero) {
          ctx.rotate(rotationAngle);
          ctx.scale(Math.cos(flipAngle), 1);
        } else {
          // Edition coins show front face only with slight rotation
          ctx.rotate(rotationAngle * 0.3);
        }

        // Draw reeded edge first (behind faces)
        if (isHero) {
          drawReededEdge(ctx);
        }

        // Calculate which face to show based on flip progress
        const isFront = flipProgress <= 0.5;

        // Apply perspective effect for flip
        ctx.scale(1, Math.cos(flipAngle));

        // Draw the appropriate face
        if (isHero) {
          drawFace(ctx, isFront);
        } else {
          // Edition coins always show front face with slight rotation
          drawFace(ctx, true);
        }

        // Draw specular highlight on top
        if (isHero) {
          drawSpecularHighlight(ctx);
        }

        ctx.restore();

        // Draw shadow for hero coin only
        if (isHero) {
          drawShadow(ctx);
        }
      }

      // Animation loop
      function animate() {
        if (!isHero) return;

        time += 0.015;
        rotationAngle = time * 2; // Constant rotation
        flipProgress = (Math.sin(time) + 1) / 2; // Smooth flip between 0 and 1

        render();
      }

      // Start animation for hero coin only
      if (isHero) {
        animate();
      } else {
        render(); // Static render for edition coins
      }

      return {
        setTime: function(t) {
          time = t;
          rotationAngle = t * Math.PI * 2; // Full rotation per loop
          flipProgress = (Math.sin(t * Math.PI) + 1) / 2; // Flip cycle

          render();
        },
        pause: function() {
          // Animation is already stopped for edition coins, hero coin doesn't auto-animate when paused
        }
      };
    }

    // Initialize hero coin renderer
    const heroCanvas = document.getElementById('coin-hero');
    window.demo = createCoinRenderer(heroCanvas, true);

    // Initialize edition coin renderers
    const editionCanvases = document.querySelectorAll('.edition-canvas');

    editionCanvases.forEach(canvas => {
      createCoinRenderer(canvas, false);
    });

    // Add hover effects for hero coin interaction
    heroCanvas.addEventListener('mousemove', function(e) {
      if (!window.demo) return;

      const rect = this.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      // Adjust rotation based on mouse position (only affects visual, not state)
      window.demo.pause();
    });

    // Add click interaction for hero coin
    heroCanvas.addEventListener('click', function() {
      if (!window.demo) return;

      // Reset animation briefly to draw attention
      const originalTime = window.demo.time || 0;
      window.demo.setTime(0);
      setTimeout(() => {
        window.demo.setTime(originalTime);
      }, 500);
    });

    // Initialize demo object with current time state
    Object.defineProperty(window.demo, 'time', {
      get: function() { return this._time || 0; },
      set: function(v) { 
        this._time = v;
        this.setTime(v); 
      }
    });

    window.demo.time = 0;

    // Add scroll animation for hero coin
    let isPaused = false;
    const observerOptions = {
      threshold: 0.5
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.target.id === 'hero') {
          if (entry.isIntersecting && !isPaused) {
            // Resume animation when visible
            window.demo.pause();
          } else {
            isPaused = true;
            window.demo.pause();
          }
        }
      });
    }, observerOptions);

    observer.observe(document.getElementById('hero'));
  </script>
